/**
	 * Get the value of the WFP cache for a post.
	 *
	 * @since 3.0.0
	 *
	 * @param int    $post_id Post ID.
	 * @param string $key     WFP Cache key.
	 * @return mixed Value of the WFP cache or false if invalid, expired or unavailable.
	 */
function get_cache( $post_id, $key ) {
		$meta_key      = '_wherego_cache_' . $key;
		$cache_expires = '_wherego_cache_expires_' . $key;

		$value = get_post_meta( $post_id, $meta_key, true );

		if ( (int) WFP_CACHE_TIME <= 0 ) {
			return $value;
		}

		if ( $value ) {
			$expires = (int) get_post_meta( $post_id, $cache_expires, true );
			if ( $expires < time() ) {
				self::delete_cache( $post_id, $key );
				return false;
			} else {
				return $value;
			}
		} else {
			return false;
		}
	}

/**
	 * Render Template
	 *
	 * @return void
	 */
function render() {
		try {
			$settings = $this->get_settings_for_display();

			if ( empty( $settings['item_layouts'] ) ) {
				return;
			}

			// Query
			$args = [
				'number'   => $settings['limit'] ?? 5,
				'role__in' => [ 'lp_teacher', 'administrator' ],
				'fields'   => 'ID',
			];

			switch ( $settings['order_by'] ?? '' ) {
				case 'desc_name':
					$args['orderby'] = 'display_name';
					$args['order']   = 'desc';
					break;
				case 'name':
				default:
					$args['orderby'] = 'display_name';
					$args['order']   = 'asc';
					break;
			}

			$query = new WP_User_Query( $args );

			$instructors = $query->get_results();
			// End Query

			$item_layout = $settings['item_layouts'][0];
			if ( ! empty( $item_layout['layout_custom_css'] ) ) {
				$item_layout['layout_custom_css'] = preg_replace(
					'/selector/i',
					".elementor-repeater-item-{$item_layout['_id']}",
					$item_layout['layout_custom_css']
				);
				echo '<style id="' . esc_attr( $this->get_id() ) . '">' . $item_layout['layout_custom_css'] . '</style>';
			}

			// Show list instructors
			ob_start();
			$singleInstructorTemplate = SingleInstructorTemplate::instance();
			echo '<ul class="list-instructors">';
			foreach ( $instructors as $instructor_id ) {
				$instructor = UserModel::find( $instructor_id, true );
				if ( ! $instructor ) {
					continue;
				}
				?>
				<li class="item-instructor">
					<?php
					echo $singleInstructorTemplate->render_data(
						$instructor,
						wp_kses_post( html_entity_decode( $item_layout['layout_html'] ) )
					);
					?>
				</li>
				<?php
			}
			echo '</ul>';
			$content = ob_get_clean();

			$section = [
				'wrapper'     => sprintf(
					'<div class="%s">',
					'elementor-repeater-item-' . esc_attr( $item_layout['_id'] ?? '' )
				),
				'content'     => $content,
				'wrapper_end' => '</div>',
			];

			echo Template::combine_components( $section );
			// End show list instructors
		}

