/**
		 * Add new answer.
		 *
		 * @param $question_id
		 * @param $new_answer
		 *
		 * @return bool|false|int
		 */
function new_answer( $question_id, $new_answer ) {
			if ( learn_press_get_post_type( $question_id ) !== LP_QUESTION_CPT ) {
				return false;
			}

			$question = LP_Question::get_question( $question_id );

			// exist answer options
			$answers = $question->get_data( 'answer_options' );
			// number answer options
			$number = count( $answers );

			if ( $question->get_type() === 'sorting_choice' ) {
				$new_answer['is_true'] = 'yes';
			}

			global $wpdb;

			$new_answer = wp_parse_args(
				$new_answer,
				array(
					'question_id' => $question_id,
					'title'       => '',
					'value'       => learn_press_random_value(),
					'is_true'     => '',
					'order'       => $number + 1,
				)
			);

			$insert = $wpdb->insert(
				$wpdb->learnpress_question_answers,
				$new_answer,
				learn_press_map_columns_format(
					$new_answer,
					array(
						'question_id' => '%d',
						'title'       => '%s',
						'value'       => '%s',
						'is_true'     => '%s',
						'order'       => '%d',
					)
				)
			);

			if ( $insert ) {
				$new_answer['question_answer_id'] = $wpdb->insert_id;

				if ( is_array( $answers ) ) {
					$answers = array_merge( $answers, array( $new_answer ) );
				} else {
					$answers = array( $new_answer );
				}
				$question->set_data( 'answer_options', $answers );
			}

			return $wpdb->insert_id;
		}

/**
	 * Get result/processing course
	 *
	 * @param string $prop
	 *
	 * @return mixed
	 */
function get_result( $prop = '' ) {
		$results = $this->calculate_course_results();

		// Fix temporary for case call 'grade' - addons called
		if ( 'grade' === $prop ) {
			if ( $results['pass'] ) {
				$results['grade'] = 'passed';
			} else {
				$results['grade'] = 'failed';
			}
		}

		return $prop && $results && array_key_exists( $prop, $results ) ? $results[ $prop ] : $results;
	}

function save( $post_id ) {
		$data   = LP_Request::get_param( $this->id, $this->default ?? [], 'html' );
		$output = array();

		if ( ! empty( $data ) && is_array( $data ) ) {
			foreach ( $data as $key => $val ) {
				foreach ( $this->extra['fields'] as $field_key => $field ) {
					if ( get_class( $field ) === 'LP_Meta_Box_Checkbox_Field' ) {
						$val[ $field_key ] = isset( $val[ $field_key ] ) ? 'yes' : 'no';
					}
				}

				$sort_key = $val['sort'];
				unset( $val['sort'] );

				$output[ $sort_key ] = $val;
			}
		}

		update_post_meta( $post_id, $this->id, $output );

		return $output;
	}

/**
	 * Function to add item on Cart Melhor Envio
	 *
	 * @param int   $orderId
	 * @param array $products
	 * @param array $dataBuyer
	 * @param int   $shippingMethodId
	 * @return array
	 */
function add( $orderId, $products, $dataBuyer, $shippingMethodId, $nonCommercial = true ) {

		$nonCommercial = ($nonCommercial === "true");

		$body = $this->createPayloadToCart( $orderId, $products, $dataBuyer, $shippingMethodId, $nonCommercial);

		$errors = $this->validatePayloadBeforeAddCart( $body, $orderId );

		if ( ! empty( $errors ) ) {
			return array(
				'success' => false,
				'errors'  => $errors,
			);
		}

		$result = ( new RequestService() )->request(
			self::ROUTE_MELHOR_ENVIO_ADD_CART,
			'POST',
			$body,
			true
		);

		if ( ! empty( $result->errors ) ) {
			return array(
				'success' => false,
				'errors'  => end( $result->errors ),
			);
		}

		if ( empty( $result->id ) ) {
			return array(
				'success' => false,
				'errors'  => 'Não foi possível enviar o pedido para o carrinho de compras',
			);
		}

		return ( new OrderQuotationService() )->updateDataQuotation(
			$orderId,
			$result->id,
			$result->protocol,
			Order::STATUS_PENDING,
			$shippingMethodId,
			null,
			$result->self_tracking
		);
	}

/**
	 * @param array $args
	 *
	 * @return bool
	 */
function new_question( $args = array() ) {
		$question = ! empty( $args['question'] ) ? $args['question'] : false;
		$question = json_decode( wp_unslash( $question ), true );

		if ( ! $question ) {
			return false;
		}

		$quiz_id = $this->quiz->get_id();

		// draft quiz
		if ( get_post_status( $quiz_id ) == 'auto-draft' ) {

			$draft_quiz = ! empty( $args['draft_quiz'] ) ? $args['draft_quiz'] : '';
			$draft_quiz = (array) ( json_decode( wp_unslash( $draft_quiz ), '' ) );

			$quiz_args = array(
				'id'      => $this->quiz->get_id(),
				'title'   => $draft_quiz['title'] ? $draft_quiz['title'] : __( 'New Quiz', 'learnpress' ),
				'content' => $draft_quiz['content'],
				'status'  => 'draft',
			);

			$quiz_id = $this->quiz_curd->create( $quiz_args );
		}

		if ( ! isset( $quiz_id ) ) {
			$this->result = new WP_Error( 'CREATE_QUIZ_FAILED', __( 'Quiz creation failed.', 'learnpress' ) );

			return false;
		}

		$args = array(
			'quiz_id' => $quiz_id,
			'title'   => $question['title'],
			'type'    => $question['type'],
		);

		$new_question = $this->question_curd->create( $args );
		$this->clear_cache_of_quiz_questions( $quiz_id );

		if ( ! is_wp_error( $new_question ) ) {
			// update hidden questions in quiz meta
			$quiz             = LP_Quiz::get_quiz( $quiz_id );
			$hidden_questions = $quiz->get_question_ids();

			if ( $hidden_questions ) {
				$index = array_search( $new_question->get_id(), $hidden_questions );
				if ( $index !== false ) {
					unset( $hidden_questions[ $index ] );
				}
				//$hidden_questions = array_keys( $hidden_questions );
			}

			update_post_meta( $quiz_id, '_lp_hidden_questions', $hidden_questions );

			// get new question data
			$this->result = $this->get_question_data_to_quiz_editor( $new_question, true, array( 'open' => true ) );

			if ( isset( $question['id'] ) ) {
				$this->result['temp_id'] = $question['id'];
			}

			return true;
		}

		return false;
	}

/**
	 * Creates and returns a new zero-value row for provided date and metrics.
	 *
