/**
     * Parse comma separated selector list
     *
     * @param array $out
     * @param string|bool $subSelector
     *
     * @return bool
     */
function selectors(&$out, $subSelector = false): bool
    {
        $s = $this->count;
        $selectors = [];

        while ($this->selector($sel, $subSelector)) {
            $selectors[] = $sel;

            if (! $this->matchChar(',', true)) {
                break;
            }

            while ($this->matchChar(',', true)) {
                ; // ignore extra
            }
        }

        if (! $selectors) {
            $this->seek($s);

            return false;
        }

        $out = $selectors;

        return true;
    }

