/**
	 * Get translation string single/plural
	 *
	 * @param float $number
	 * @param string $string_value
	 * @param bool $include_number
	 *
	 * @return string
	 * @since 4.2.7.4
	 * @version 1.0.0
	 */
function get_i18n_string_plural( float $number, string $string_value = '', bool $include_number = true ): string {
		switch ( $string_value ) {
			case LP_COURSE_CPT:
				$plural = sprintf(
					_n( 'Course', 'Courses', $number, 'learnpress' ),
					$number
				);
				break;
			case LP_LESSON_CPT:
				$plural = sprintf(
					_n( 'Lesson', 'Lessons', $number, 'learnpress' ),
					$number
				);
				break;
			case LP_QUIZ_CPT:
				$plural = sprintf(
					_n( 'Quiz', 'Quizzes', $number, 'learnpress' ),
					$number
				);
				break;
			case LP_QUESTION_CPT:
				$plural = sprintf(
					_n( 'Question', 'Questions', $number, 'learnpress' ),
					$number
				);
				break;
			case 'lp_assignment':
				$plural = sprintf(
					_n( 'Assignment', 'Assignments', $number, 'learnpress' ),
					$number
				);
				break;
			case 'lp_h5p':
				$plural = sprintf(
					_n( 'H5P', 'H5Ps', $number, 'learnpress' ),
					$number
				);
				break;
			default:
				$plural = $string_value;
				break;
		}

		if ( $include_number ) {
			$plural = sprintf( '%s %s', $number, $plural );
		}

		return apply_filters( 'learn-press/i18n/plural', $plural, $number, $string_value, $include_number );
	}

/**
	 * Internal function to perform the mysqli_query() call.
	 *
	 * @since 3.9.0
	 *
	 * @see wpdb::query()
	 *
	 * @param string $query The query to run.
	 */
function _do_query( $query ) {
		if ( defined( 'SAVEQUERIES' ) && SAVEQUERIES ) {
			$this->timer_start();
		}

		if ( ! empty( $this->dbh ) ) {
			$this->result = mysqli_query( $this->dbh, $query );
		}

		++$this->num_queries;

		if ( defined( 'SAVEQUERIES' ) && SAVEQUERIES ) {
			$this->log_query(
				$query,
				$this->timer_stop(),
				$this->get_caller(),
				$this->time_start,
				array()
			);
		}
	}

