					 *
					 * @since 6.0.0
					 * @param string $tax_label Tax label.
					 * @param \WC_Order $order Order object.
					 * @param string $tax_display Tax display.
					 * @return string
					 */
function show_local_pickup_details( $return_value, $order ) {
		// Confirm order is valid before proceeding further.
		if ( ! $order instanceof \WC_Order ) {
			return $return_value;
		}

		$shipping_method_ids = ArrayUtil::select( $order->get_shipping_methods(), 'get_method_id', ArrayUtil::SELECT_BY_OBJECT_METHOD );
		$shipping_method_id  = current( $shipping_method_ids );

		// Ensure order used pickup location method, otherwise bail.
		if ( 'pickup_location' !== $shipping_method_id ) {
			return $return_value;
		}

		$shipping_method = current( $order->get_shipping_methods() );
		$details         = $shipping_method->get_meta( 'pickup_details' );
		$location        = $shipping_method->get_meta( 'pickup_location' );
		$address         = $shipping_method->get_meta( 'pickup_address' );
		$cost            = $shipping_method->get_total();

		$lines = array();

		if ( $location ) {
			$lines[] = sprintf(
				// Translators: %s location name.
				__( 'Collection from <strong>%s</strong>:', 'woocommerce' ),
				$location
			);
		}

		if ( $address ) {
			$lines[] = nl2br( esc_html( str_replace( ',', ', ', $address ) ) );
		}

		if ( $details ) {
			$lines[] = wp_kses_post( $details );
		}

		if ( $cost > 0 ) {
			$tax_display = get_option( 'woocommerce_tax_display_cart' );
			$tax         = $shipping_method->get_total_tax();

			// Format cost with tax handling.
			if ( 'excl' === $tax_display ) {
				// Show pickup cost excluding tax.
				$formatted_cost = wc_price( $cost, array( 'currency' => $order->get_currency() ) );
				if ( (float) $tax > 0 && $order->get_prices_include_tax() ) {

					$formatted_cost .= apply_filters(
						'woocommerce_order_shipping_to_display_tax_label',
						'&nbsp;<small class="tax_label">' . WC()->countries->ex_tax_or_vat() . '</small>',
						$order,
						$tax_display
					);
				}
			} else {
				// Show pickup cost including tax.
				$formatted_cost = wc_price(
					(float) $cost + (float) $tax,
					array( 'currency' => $order->get_currency() )
				);
				if ( (float) $tax > 0 && ! $order->get_prices_include_tax() ) {

					$formatted_cost .= apply_filters(
						'woocommerce_order_shipping_to_display_tax_label',
						'&nbsp;<small class="tax_label">' . WC()->countries->inc_tax_or_vat() . '</small>',
						$order,
						$tax_display
					);
				}
			}

			$lines[] = '<br>' . sprintf(
				// Translators: %s is the formatted price.
				__( 'Pickup cost: %s', 'woocommerce' ),
				$formatted_cost
			);
		}

		// If nothing is available, return original.
		if ( empty( $lines ) ) {
			return $return_value;
		}

		// Join all the lines with a <br> separator.
		return implode( '<br>', $lines );
	}

/**
		 * If no original image was provided the image_directory can't be determined, in that scenario try to
		 * find it from the `file` property.
		 *
		 * @see get_attached_file()
		 */
function webp_uploads_update_sources( array $metadata, array $valid_mime_transforms, array $main_images, array $subsized_images ): array {
	foreach ( $valid_mime_transforms as $targeted_mime ) {
		// Make sure the path and file exists as those values are required.
		$image_directory = null;
		if ( isset( $main_images[ $targeted_mime ]['path'], $main_images[ $targeted_mime ]['file'] ) && file_exists( $main_images[ $targeted_mime ]['path'] ) ) {
			// Add sources to original image metadata.
			$metadata['sources'][ $targeted_mime ] = array(
				'file'     => $main_images[ $targeted_mime ]['file'],
				'filesize' => wp_filesize( $main_images[ $targeted_mime ]['path'] ),
			);
			$image_directory                       = pathinfo( $main_images[ $targeted_mime ]['path'], PATHINFO_DIRNAME );
		}


		if (
			null === $image_directory
			&& isset( $metadata['file'] )
			&& 0 !== strpos( $metadata['file'], '/' )
			&& ':\\' !== substr( $metadata['file'], 1, 2 )
		) {
			$uploads = wp_get_upload_dir();
			if ( false === $uploads['error'] && isset( $uploads['basedir'] ) ) {
				$file = path_join( $uploads['basedir'], $metadata['file'] );
				if ( file_exists( $file ) ) {
					$image_directory = pathinfo( $file, PATHINFO_DIRNAME );
				}
			}
		}

		if ( null === $image_directory ) {
			continue;
		}

		foreach ( $metadata['sizes'] as $size_name => $size_details ) {
			if (
				! isset( $subsized_images[ $targeted_mime ][ $size_name ]['file'] ) ||
				! is_string( $subsized_images[ $targeted_mime ][ $size_name ]['file'] ) ||
				'' === $subsized_images[ $targeted_mime ][ $size_name ]['file']
			) {
				continue;
			}

			// Add sources to resized image metadata.
			$subsize_path = path_join( $image_directory, $subsized_images[ $targeted_mime ][ $size_name ]['file'] );
			if ( ! file_exists( $subsize_path ) ) {
				continue;
			}

			$metadata['sizes'][ $size_name ]['sources'][ $targeted_mime ] = array(
				'file'     => $subsized_images[ $targeted_mime ][ $size_name ]['file'],
				'filesize' => wp_filesize( $subsize_path ),
			);
		}
	}

	return $metadata;
}

