/**
	 * Validate required fields are present.
	 *
	 * @since 10.5.0
	 * @param array $row Product data row.
	 * @return array Validation errors.
	 */
function validate_required_fields( array $row ): array {
		$errors          = [];
		$required_fields = WC_Stripe_Agentic_Commerce_Feed_Schema::get_required_fields();

		foreach ( $required_fields as $field ) {
			if ( ! isset( $row[ $field ] ) || '' === $row[ $field ] ) {
				$errors[] = sprintf(
					/* translators: %s: field name */
					__( 'Required field "%s" is missing or empty.', 'woocommerce-gateway-stripe' ),
					$field
				);
			}
		}

		// Validate conditionally required fields.
		$errors = array_merge( $errors, $this->validate_conditional_requirements( $row ) );

		return $errors;
	}

/**
	 * Render the block.
	 *
	 * @param array    $attributes Block attributes.
	 * @param string   $content Block content.
	 * @param WP_Block $block Block instance.
	 * @return string Rendered block content.
	 */
function render( $attributes, $content, $block ) {
		if ( ! isset( $block->context['commentId'] ) ) {
			return '';
		}

		$comment = get_comment( $block->context['commentId'] );
		if ( empty( $comment ) ) {
			return '';
		}

		$classes = ( isset( $attributes['style']['elements']['link']['color']['text'] ) ) ? 'has-link-color' : '';

		$wrapper_attributes = get_block_wrapper_attributes( array( 'class' => $classes ) );
		if ( isset( $attributes['format'] ) && 'human-diff' === $attributes['format'] ) {
			// translators: %s: human-readable time difference.
			$formatted_date = sprintf( __( '%s ago', 'woocommerce' ), human_time_diff( get_comment_date( 'U', $comment ) ) );
		} else {
			$formatted_date = get_comment_date( empty( $attributes['format'] ) ? '' : $attributes['format'], $comment );
		}
		$link = get_comment_link( $comment );

		if ( ! empty( $attributes['isLink'] ) ) {
			$formatted_date = sprintf( '<a href="%1s">%2s</a>', esc_url( $link ), $formatted_date );
		}

		return sprintf(
			'<div %1$s><time datetime="%2$s">%3$s</time></div>',
			$wrapper_attributes,
			esc_attr( get_comment_date( 'c', $comment ) ),
			$formatted_date
		);
	}

