/**
	 * Prevents deletion of order backup posts (regardless of sync setting) when HPOS is authoritative and the order
	 * still exists in HPOS.
	 * This should help with edge cases where wp_delete_post() would delete the HPOS record too or backfill would sync
	 * incorrect data from an order with no metadata from the posts table.
	 *
	 * @since 8.8.0
	 *
	 * @param WP_Post|false|null $delete Whether to go forward with deletion.
	 * @param WP_Post            $post   Post object.
	 * @return WP_Post|false|null
	 *
	 * @internal For exclusive usage of WooCommerce core, backwards compatibility not guaranteed.
	 */
function maybe_prevent_deletion_of_post( $delete, $post ) {
		if ( self::PLACEHOLDER_ORDER_POST_TYPE !== $post->post_type && $this->custom_orders_table_is_authoritative() && $this->data_store->order_exists( $post->ID ) ) {
			$delete = false;
		}

		return $delete;
	}

/** @var array<string, QM_Output_Headers> $outputters */
function filter_wp_redirect( $location, $status ) {

		if ( ! $this->should_dispatch() ) {
			return $location;
		}

		$this->before_output();


		$outputters = $this->get_outputters( 'headers' );

		foreach ( $outputters as $output ) {
			$output->output();
		}

		$this->after_output();

		return $location;

	}

/**
	 * Install Theme.
	 */
function grigora_st_install_theme() {
		check_ajax_referer( 'grigora-st', '_nonce' );

		// Sanitization.
		$notskip = rest_sanitize_boolean( $_POST['notskip'] );
		$slug    = sanitize_key( wp_unslash( $_POST['slug'] ) );

		if ( false === $notskip ) {
			wp_send_json_success(
				array(
					'success' => true,
				)
			);
		}
		if ( empty( $slug ) ) {
			wp_send_json_success(
				array(
					'success' => true,
					'message' => __( 'No theme specified, using current theme', 'grigora-kit' ),
				)
			);
		}

		if ( wp_get_theme( $slug )->exists() ) {
			wp_send_json_success(
				array(
					'success' => true,
					'message' => __( 'Theme already installed.', 'grigora-kit' ),
				)
			);
		}

		$status = array(
			'install' => 'theme',
			'slug'    => $slug,
		);

		if ( ! current_user_can( 'install_themes' ) ) {
			wp_send_json_error( __( 'Sorry, you are not allowed to install themes on this site.', 'grigora-kit' ) );
		}

		require_once ABSPATH . 'wp-admin/includes/class-wp-upgrader.php';
		include_once ABSPATH . 'wp-admin/includes/theme.php';

		$api = themes_api(
			'theme_information',
			array(
				'slug'   => $slug,
				'fields' => array( 'sections' => false ),
			)
		);

		if ( is_wp_error( $api ) ) {
			wp_send_json_error( $api->get_error_message() );
		}

		$skin     = new WP_Ajax_Upgrader_Skin();
		$upgrader = new Theme_Upgrader( $skin );
		$result   = $upgrader->install( $api->download_link );

		if ( defined( 'WP_DEBUG' ) && WP_DEBUG ) {
			$status['debug'] = $skin->get_upgrade_messages();
		}

		if ( is_wp_error( $result ) ) {
			$status['errorCode']    = $result->get_error_code();
			$status['errorMessage'] = $result->get_error_message();
			wp_send_json_error( $status );
		} elseif ( is_wp_error( $skin->result ) ) {
			$status['errorCode']    = $skin->result->get_error_code();
			$status['errorMessage'] = $skin->result->get_error_message();
			wp_send_json_error( $status );
		} elseif ( $skin->get_errors()->has_errors() ) {
			$status['errorMessage'] = $skin->get_error_messages();
			wp_send_json_error( $skin->get_error_message() );
		} elseif ( is_null( $result ) ) {
			global $wp_filesystem;

			$status['errorCode']    = 'unable_to_connect_to_filesystem';
			$status['errorMessage'] = __( 'Unable to connect to the filesystem. Please confirm your credentials.', 'grigora-kit' );

			// Pass through the error from WP_Filesystem if one was raised.
			if ( $wp_filesystem instanceof WP_Filesystem_Base && is_wp_error( $wp_filesystem->errors ) && $wp_filesystem->errors->has_errors() ) {
				$status['errorMessage'] = esc_html( $wp_filesystem->errors->get_error_message() );
			}
			wp_send_json_error( $status );
		}

		$status['themeName'] = wp_get_theme( $slug )->get( 'Name' );

		if ( ! is_multisite() && current_user_can( 'edit_theme_options' ) && current_user_can( 'customize' ) ) {
			$status['customizeUrl'] = add_query_arg(
				array(
					'return' => rawurlencode( network_admin_url( 'theme-install.php', 'relative' ) ),
				),
				wp_customize_url( $slug )
			);
		}
		wp_send_json_success(
			array(
				'success' => true,
				'message' => __( 'Grigora Blocks Installed', 'grigora-kit' ),
				'data'    => $status,
			)
		);
	}

