/**
		 * Array of `true` values for each product IDs already handled by this method. Used to prevent double submission.
		 *
		 * @var bool[] $already_updated
		 */
function handle_update_product( WC_Product $product ) {

		static $already_updated = [];
		if ( isset( $already_updated[ $product->get_id() ] ) ) {
			return;
		}

		$form           = $this->get_form( $product );
		$form_view_data = $form->get_view_data();

		// phpcs:disable WordPress.Security.NonceVerification
		if ( empty( $_POST[ $form_view_data['name'] ] ) ) {
			return;
		}
		// phpcs:ignore WordPress.Security.ValidatedSanitizedInput.InputNotSanitized
		$submitted_data = (array) wc_clean( wp_unslash( $_POST[ $form_view_data['name'] ] ) );
		// phpcs:enable WordPress.Security.NonceVerification

		$form->submit( $submitted_data );
		$this->update_data( $product, $form->get_data() );

		$already_updated[ $product->get_id() ] = true;
	}

/**
		 * @return bool|LP_User|LP_User_Guest|WP_Error
		 */
function can_view_profile() {
			global $wp;

			$current_user = learn_press_get_current_user();
			$viewing_user = true;

			if ( ! current_user_can( ADMIN_ROLE ) ) {
				if ( empty( $wp->query_vars['user'] ) ) {
					$viewing_user = $current_user;
				} else {
					$request_user = urldecode( (string) $wp->query_vars['user'] );
					$user_model   = new UserModel();
					$wp_user      = $user_model->resolve_user_by_public_identifier( $request_user );

					if ( $wp_user ) {
						$viewing_user = learn_press_get_user( $wp_user->ID );

						if ( $viewing_user->is_guest() ) {
							$viewing_user = false;
						}
					}
				}
			}

			$viewing_user = apply_filters( 'learn-press/profile/can-view-user', $viewing_user );

			if ( ! $viewing_user ) {
				return new WP_Error( 'cannot-view-profile', esc_html__( 'You can\'t view the user profile', 'learnpress' ) );
			}

			return $viewing_user;
		}

