		'product',
		'edit-shop_coupon',
		'shop_coupon',
		'edit-product_cat',
		'edit-product_tag',
		'edit-product-brand',
		'profile',
		'user-edit',
	);

	foreach ( wc_get_order_types() as $type ) {
