/**
	 * Render content of block tag
	 *
	 * @param array $attributes | Attributes of block tag.
	 *
	 * @return false|string
	 */
function render_content_block_template( array $attributes, $content, $block ): string {
		$html = '';

		try {
			$courseModel = $this->get_course( $attributes, $block );
			if ( ! $courseModel ) {
				return $html;
			}

			$userModel = $this->get_user();
			if ( $userModel instanceof UserModel ) {
				$userCourseModel = UserCourseModel::find( $userModel->get_id(), $courseModel->get_id(), true );
				if ( $userCourseModel ) {
					return $html;
				}
			}

			$html_price = SingleCourseTemplate::instance()->html_price( $courseModel );
			if ( empty( $html_price ) ) {
				return $html;
			}

			$html = $this->get_output( $html_price );
		} catch ( Throwable $e ) {
			LP_Debug::error_log( $e );
		}

		return $html;
	}

