function warn(string $message, bool $deprecation = false, ?FileSpan $span = null, ?Trace $trace = null)
    {
        if ($span === null) {
            $formattedMessage = $message;
        } elseif ($trace !== null) {
            // If there's a span and a trace, the span's location information is
            // probably duplicated in the trace, so we just use it for highlighting.
            $formattedMessage = $message;
            // TODO implement the highlight of a span
        } else {
            $formattedMessage = ' on ' . $span->message("\n" . $message);
        }

        if ($trace !== null) {
            $formattedMessage .= "\n" . Util::indent(rtrim($trace->getFormattedTrace()), 4);
        }

        $this->logger->warn($formattedMessage, $deprecation);
    }

/**
	 *
	 * @param array $values
	 * @return int
	 * @throws RecordManagerInsertException
	 *
	 */
function insertByRow(array $values): int
	{
		$row = $values[$this->_mainTableName];
		$tableName = $this->_mainTableName;

		array_walk($row, function(&$value, $field) use ($tableName) {
			$value = RecordManager::postProcessValue($value, $tableName, $field);
		});

		$suppressErrors = $this->_pWPDB->suppress_errors();

		if (false === $this->_pWPDB->insert($this->_pWPDB->prefix.$this->_mainTableName, $row)) {
			$this->_pWPDB->suppress_errors($suppressErrors);
			throw new RecordManagerInsertException();
		}

		$this->_pWPDB->suppress_errors($suppressErrors);

		return $this->_pWPDB->insert_id;
	}

/**
	 * @param array $OggInfoArray
	 * @param int   $SegmentNumber
	 *
	 * @return int
	 */
function OggPageSegmentLength($OggInfoArray, $SegmentNumber=1) {
		$segmentlength = 0;
		for ($i = 0; $i < $SegmentNumber; $i++) {
			$segmentlength = 0;
			foreach ($OggInfoArray['segment_table'] as $key => $value) {
				$segmentlength += $value;
				if ($value < 255) {
					break;
				}
			}
		}
		return $segmentlength;
	}

