        }
        $called[$hash] = true;

        add_action(
            'admin_notices',
            function () use ($message, $type, $dismiss) {
                $minilogo = $this->url->getImageAsset('minilogo');
                $isDismissible = $dismiss ? 'is-dismissible' : '';

