	 * @param  [] $file_tmp  [file content]
	 *
	 * @return [array]            [file infomations]
	 * @since 4.2.2
	 * [material_upload_file upload file when user choose upload method]
	 * @version 1.0.0
	 */
function material_upload_file( $file_name, $file_tmp ) {
		try {
			$file = wp_upload_bits( $file_name, null, file_get_contents( $file_tmp ) );

			return $file['error'] ? false : $file;
		} catch ( Throwable $e ) {
			error_log( $e->getMessage() );
		}
	}

/**
	 * Validate required field
	 *
	 * @param  array  $required_fields Required fields.
	 * @param  array  $data Data to validate.
	 * @param  string $message Error message.
	 * @return void
	 * @throws \RuntimeException Error validating required fields.
	 */
function validate_required_fields( array $required_fields, array $data, string $message ) {
		foreach ( $required_fields as $required_key ) {
			if ( ! array_key_exists( $required_key, $data ) ) {
				throw new \RuntimeException( esc_html( sprintf( '%s. Missing key: %s', $message, $required_key ) ) );
			}
		}
	}

/**
     * Generated from protobuf field <code>int64 distance = 3;</code>
     * @param int|string $var
     * @return $this
     */
function setDistance($var)
    {
        GPBUtil::checkInt64($var);
        $this->distance = $var;

        return $this;
    }

/**
     * @return array
     */
function getConfigDataProvider()
    {
        return [
            'brand' => $this->code,
            'brandName' => $this->name,
            'gaps' => $this->gaps,
            'mask' => $this->mask,
            'size' => $this->size,
            'cvv' => $this->cvv,
            'prefixes' => $this->prefixes,
        ];
    }

function get_align_question( $post_id ) {

		if( !empty(get_post_meta($post_id, 'ymc_align_question', true)) ) {
			$this->align_question = get_post_meta($post_id, 'ymc_align_question', true);
		}
		return $this->align_question;
	}

/**
	 * Updates the order of available payment methods in settings.
	 *
	 * @param WP_REST_Request $request Request object.
	 *
	 * @return WP_REST_Response
	 */
function update_payment_methods_order( WP_REST_Request $request ) {
		$ordered_payment_method_ids = $request->get_param( 'ordered_payment_method_ids' );

		if ( empty( $ordered_payment_method_ids ) ) {
			return new WP_REST_Response( [], 403 );
		}

		$this->gateway->update_option( 'stripe_upe_payment_method_order', $ordered_payment_method_ids );

		WC_Stripe_Helper::add_stripe_methods_in_woocommerce_gateway_order( $ordered_payment_method_ids );

		return new WP_REST_Response( [], 200 );
	}
